// Generated by OrchestKit Claude Plugin
// Created: 2026-06-07

// Unified search index builder — feeds the global ⌘K search (app/api/search).
//
// Replaces the previous title-only fumadocs default. One Orama index covers:
//   • docs prose pages          (MDX, already in source)
//   • skill / agent / hook pages (MDX reference pages — re-tagged + body-enriched)
//   • compositions               (data-only — injected as synthetic records)
//
// Each record carries a `tag` ("docs" | "skill" | "agent" | "hook" | "composition")
// so the search dialog can offer Docs / Skills / Agents tabs (see components/search-dialog).
// Full skill bodies and structured tags/keywords are appended to each record's
// structuredData so they rank in results — closing the "search misses content" gap.

import { source } from "@/lib/source";
import { SKILLS } from "@/lib/generated/skills-data";
import { SKILL_CONTENT } from "@/lib/generated/skill-content-data";
import { AGENTS } from "@/lib/generated/agents-data";
import { COMPOSITIONS } from "@/lib/generated/compositions-data";
import type { AdvancedIndex } from "fumadocs-core/search/server";
import type { StructuredData } from "fumadocs-core/mdx-plugins";

export const SEARCH_TAGS = [
  "docs",
  "skill",
  "agent",
  "hook",
  "composition",
] as const;
export type SearchTag = (typeof SEARCH_TAGS)[number];

/** Derive the content-type tag from a docs page URL. */
function tagForUrl(url: string): SearchTag {
  if (url.startsWith("/docs/reference/skills") || url.startsWith("/docs/skills"))
    return "skill";
  if (url.startsWith("/docs/reference/agents") || url.startsWith("/docs/agents"))
    return "agent";
  if (url.startsWith("/docs/reference/hooks") || url.startsWith("/docs/hooks"))
    return "hook";
  return "docs";
}

/** Slug of a reference page, e.g. /docs/reference/skills/assess -> "assess". */
function lastSlug(url: string): string {
  const parts = url.split("/").filter(Boolean);
  return parts[parts.length - 1] ?? "";
}

/** Append extra paragraphs to a page's structured data so they become searchable. */
function withExtraContent(
  base: StructuredData,
  extras: string[],
): StructuredData {
  const contents = [...base.contents];
  for (const content of extras) {
    const trimmed = content?.trim();
    if (trimmed) contents.push({ heading: undefined, content: trimmed });
  }
  return { headings: base.headings, contents };
}

/** Synthetic structured data for non-MDX records (compositions). */
function plainStructure(paragraphs: string[]): StructuredData {
  return {
    headings: [],
    contents: paragraphs
      .map((p) => p?.trim())
      .filter((p): p is string => Boolean(p))
      .map((content) => ({ heading: undefined, content })),
  };
}

/**
 * Build the full set of search indexes. Passed to createSearchAPI('advanced').
 * Re-evaluated lazily on first search (and on dev rebuilds).
 */
export function buildSearchIndexes(): AdvancedIndex[] {
  const indexes: AdvancedIndex[] = [];

  // 1. All docs pages (prose + reference), tagged by content type and enriched.
  for (const page of source.getPages()) {
    const tag = tagForUrl(page.url);
    const base: StructuredData = page.data.structuredData ?? {
      headings: [],
      contents: [],
    };
    const extras: string[] = [];

    if (tag === "skill") {
      const slug = lastSlug(page.url);
      const meta = SKILLS[slug];
      if (meta?.tags?.length) extras.push(meta.tags.join(", "));
      // Inject the full skill body (reference MDX is only a summary) so deep
      // content (rules, patterns, examples) is searchable in the global index.
      const body = SKILL_CONTENT[slug]?.content;
      if (body) extras.push(body);
    } else if (tag === "agent") {
      const slug = lastSlug(page.url);
      const agent = AGENTS.find((a) => a.name === slug);
      if (agent?.keywords?.length) extras.push(agent.keywords.join(", "));
      if (agent?.taskTypes?.length) extras.push(agent.taskTypes.join(", "));
    }

    indexes.push({
      id: page.url,
      title: page.data.title,
      description: page.data.description,
      url: page.url,
      tag,
      structuredData: extras.length
        ? withExtraContent(base, extras)
        : base,
    });
  }

  // 2. Compositions — data-only, never had a page, so inject synthetic records.
  for (const c of COMPOSITIONS) {
    indexes.push({
      id: `composition-${c.id}`,
      title: c.id,
      description: c.hook,
      url: `/showcase/pipeline#${c.id}`,
      tag: "composition",
      structuredData: plainStructure([
        c.hook,
        `${c.command} · ${c.skill} · ${c.hook}`,
        (c.tags ?? []).join(", "),
        `${c.category} composition`,
      ]),
    });
  }

  return indexes;
}
